    hookCategoryName: HookCategoryNameT,
    hookName: HookNameT,
  ): Promise<Array<HardhatHooks[HookCategoryNameT][HookNameT]>> {
    let handlersByName = this.#sequentialHandlers.get(hookCategoryName);
    if (handlersByName === undefined) {
      handlersByName = new Map();
      this.#sequentialHandlers.set(hookCategoryName, handlersByName);
    }

    const cached = handlersByName.get(hookName as string);
    if (cached !== undefined) {
      return cached;
    }

    const chained = await this.#getHandlersInChainedRunningOrder(
      hookCategoryName,
      hookName,
    );

    const sequential = chained.toReversed();

    handlersByName.set(hookName as string, sequential);

    return sequential;
  }

async #getUserInterruptionManager(): Promise<UserInterruptionManagerImplementationT> {
  // Note: `await import` must run BEFORE the instance cache check so that
  // concurrent callers share a single microtask-dedupe point — otherwise
  // each suspended caller re-enters the branch and constructs its own
  // impl, so callers end up holding different impl instances and state,
  // which can cause concurrency issues.
  if (UserInterruptionManagerImplementation === undefined) {
    ({ UserInterruptionManagerImplementation } = await import(
      "./user-interruptions.js"
    ));
  }

  if (this.#userInterruptionManager === undefined) {
    this.#userInterruptionManager = new UserInterruptionManagerImplementation(
      this.#hooks,
    );
  }

  return this.#userInterruptionManager;
}

const copyFolder = (
	source: string,
	target: string,
	replacements: Record<string, string> = {},
	gitignorePatterns: string[] = [],
): void => {
	if (!existsSync(target)) {
		mkdirSync(target, {recursive: true});
	}

	const files = readdirSync(source);

	files.forEach((file) => {
		const sourcePath = join(source, file);
		const targetPath = join(target, file);

		const stat = statSync(sourcePath);

		if (stat.isDirectory()) {
			// Check if directory should be skipped based on gitignore patterns
			const shouldSkip = gitignorePatterns.some(
				(pattern) => file === pattern.replace('/', '') || (pattern.startsWith('/') && file === pattern.slice(1)),
			);

			if (!shouldSkip) {
				copyFolder(sourcePath, targetPath, replacements, gitignorePatterns);
			}
		} else {
			copyFile(sourcePath, targetPath, replacements, gitignorePatterns);
		}
	});
};

const runPnpmInstall = async (folderPath: string): Promise<void> => {
	console.log(`Installing dependencies...`);
	const {spawn} = await import('child_process');

	return new Promise((resolve, reject) => {
		// Use --ignore-workspace to ensure dependencies are installed locally
		// This prevents pnpm from treating the target folder as part of a parent workspace
		const pnpm = spawn('pnpm', ['install', '--ignore-workspace', `--no-frozen-lockfile`], {
			cwd: folderPath,
			stdio: 'inherit',
		});

		pnpm.on('close', (code) => {
			if (code === 0) {
				console.log('✓ Dependencies installed successfully!');
				resolve();
			} else {
				reject(new Error(`pnpm install failed with exit code ${code}`));
			}
		});

		pnpm.on('error', (error) => {
			reject(error);
		});
	});
};

export async function loadEnvironmentFromHardhat<
	NamedAccounts extends UnresolvedUnknownNamedAccounts = UnresolvedUnknownNamedAccounts,
	Data extends UnresolvedNetworkSpecificData = UnresolvedNetworkSpecificData,
>(
	params: {hre: HardhatRuntimeEnvironment; connection?: NetworkConnection},
	// TODO ?
	// options?: {
	// 	useChainIdOfForkedNetwork?: boolean;
	// }
): Promise<Environment<NamedAccounts, Data>> {
	const {connection, environment, provider, isFork} = await generateForkConfig(params);
	const isEDR = connection.networkConfig.type === 'edr-simulated' ? true : undefined;
	// console.log(`loading environments...`);
	return loadEnvironmentFromFiles<NamedAccounts, Data>({
		provider,
		environment,
		extra: {
			connection,
		},
		saveDeployments: isFork ? false : undefined,
		autoImpersonate: isEDR,
	});
}

